INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Jewellery Care', 'Correct packing techniques for different jewellery types — necklaces, rings, bracelets and bangles — to prevent damage during transit.', (SELECT id FROM courses WHERE name = 'Client Deliveries & Shipping'), 0);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Logistics', 'Full delivery workflow including external shipping, stock transfers, courier packaging, booking, and a whole-boutique practice exercise.', (SELECT id FROM courses WHERE name = 'Client Deliveries & Shipping'), 1);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Brand Materials', 'Reviewing Canturi''s advertising, press content and lookbooks used for client presentations, sourced from the G-Drive.', (SELECT id FROM courses WHERE name = 'Collection Inspiration'), 0);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Watch', 'Reviewing the Cubism Watch video and discussing the difference between design inspiration and technical features.', (SELECT id FROM courses WHERE name = 'Collection Inspiration'), 1);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Collection Videos', 'Watching Vimeo presentations on Primavera and Athena collections — a full one-hour version and a condensed 30-minute version.', (SELECT id FROM courses WHERE name = 'Collection Inspiration'), 2);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Collection Overview', 'Exploring the full range of Canturi collections and the High Jewels collection via the Info Portal.', (SELECT id FROM courses WHERE name = 'Collection Inspiration'), 3);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('CRM Fundamentals', 'Foundational pillars of CRM — introduction, communication guidelines, client visit management, and using JCS and Monday.com as CRM tools.', (SELECT id FROM courses WHERE name = 'CRM (Customer Relationship Management)'), 0);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('CRM Videos', 'Watching a one-hour real-life CRM visit video, covering ultrasonics and client stories.', (SELECT id FROM courses WHERE name = 'CRM (Customer Relationship Management)'), 1);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('E-Store Navigation', 'Navigating the Canturi E-Store from a client''s perspective to build familiarity with the online shopping experience.', (SELECT id FROM courses WHERE name = 'E-Store'), 0);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Colour Gems', 'Full range of colour gemstone knowledge — introduction, individual gems (emerald, ruby, sapphire, ABS, Colourburst, pearls), and advanced training using certificates and GIA resources.', (SELECT id FROM courses WHERE name = 'Gems Training'), 0);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Diamonds', 'All aspects of diamond knowledge and sales — 4Cs, GIA research, WWDS sourcing, Canturi stock, client consultation, guarantee, ratios, natural vs lab grown, sales process, and real-life stories.', (SELECT id FROM courses WHERE name = 'Gems Training'), 1);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Procedures', 'Accessing the G-Drive Procedures and Guidelines folder for business process references.', (SELECT id FROM courses WHERE name = 'Help Desk & Head Office Support'), 0);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Head Office Team', 'Learning the head office staff directory — who to contact in each department and what their role covers.', (SELECT id FROM courses WHERE name = 'Help Desk & Head Office Support'), 1);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Training Resources', 'Accessing the Loom video library to select and watch relevant training recordings and updates.', (SELECT id FROM courses WHERE name = 'Help Desk & Head Office Support'), 2);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Marketing Assets', 'Locating and using approved product images stored in the G-Drive.', (SELECT id FROM courses WHERE name = 'Help Desk & Head Office Support'), 3);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Head Office Requests', 'Submitting requests to each head office department — Creation, Finance, Gems, Admin, Pricing, Product Quotes, and Image Requests — plus using Typeforms.', (SELECT id FROM courses WHERE name = 'Help Desk & Head Office Support'), 4);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Info Portal', 'Navigating the Info Portal to access general information and resources across the business.', (SELECT id FROM courses WHERE name = 'Help Desk & Head Office Support'), 5);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('HR & Administration', 'Accessing HR and leave forms and understanding the purpose and process of the quarterly survey review.', (SELECT id FROM courses WHERE name = 'Help Desk & Head Office Support'), 6);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Searching Items', 'All JCS search methods — by collection, location, description, stock type — plus managing customer profiles, comments, wishlists, and orders due reporting.', (SELECT id FROM courses WHERE name = 'JCS Training'), 0);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Processing Sales', 'Processing new orders, purchase order payments, stock sales, stock transfers between locations, and packet processing in JCS.', (SELECT id FROM courses WHERE name = 'JCS Training'), 1);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Collection Knowledge', 'Learning and presenting the key features of all 20 Canturi collections to the manager, from Abstract and Affinity through to Stella and Radiant.', (SELECT id FROM courses WHERE name = 'Jewellery Collections'), 0);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Precious Metals', 'Canturi''s precious metals — composition and production intro, individual coaching on rose gold, white gold, yellow gold and platinum, plus a presentation exercise.', (SELECT id FROM courses WHERE name = 'Metals Training'), 0);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Monday.com Basics', 'Watching Monday.com training videos and accessing IT and Monday.com support resources via the Info Portal.', (SELECT id FROM courses WHERE name = 'Monday Training'), 0);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Pipeline Fundamentals', 'Core pipeline concepts through the induction manual, Journey of the Proposal, proposal writing practice with hero jewels, Block Out Time, and the Secret Formula video.', (SELECT id FROM courses WHERE name = 'Pipeline Management'), 0);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Pipeline Admin', 'Administrative side of pipeline management — filing proposals, yellow copies, and using the Progress Tracker to monitor pipeline totals for head office reports.', (SELECT id FROM courses WHERE name = 'Pipeline Management'), 1);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Stock Management', 'Daily and periodic stock tasks — daily count, stocktake (with Loom video), orders due reporting in JCS, and ordering new product tags.', (SELECT id FROM courses WHERE name = 'Product Admin'), 0);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Repairs', 'Full repairs workflow — intake, assess and quote, JCS go-ahead process, client collection, FOC forms, online repair submission, advanced case study, and managing repair clients.', (SELECT id FROM courses WHERE name = 'Product Care & Repairs'), 0);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Presentation Skills', 'Presenting a jewel of the day or favourite jewel to the team to build product communication confidence.', (SELECT id FROM courses WHERE name = 'Product Exercise'), 0);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Product Knowledge', 'Hands-on product knowledge exercises across earrings, bracelets, dress rings, engagement rings, ceramic and Eternal bangles, with price range awareness and client role-plays.', (SELECT id FROM courses WHERE name = 'Product Exercise'), 1);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Packaging & Presentation', 'The jewellery collection ceremony — ribbon tying technique, bag presentation standards, and ordering new packaging supplies.', (SELECT id FROM courses WHERE name = 'Visual Merchandise Displays'), 0);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Visual Standards', 'Boutique visual standards for windows and displays (per the induction manual), and how and when to order flowers.', (SELECT id FROM courses WHERE name = 'Visual Merchandise Displays'), 1);
INSERT INTO categories (title, description, course_id, sort_order) VALUES ('Watch Knowledge', 'All Canturi Watch training — product variations and dial options, five key selling points for consultations, training slides on Canva and the Info Portal, and the watch website page.', (SELECT id FROM courses WHERE name = 'Watch Training'), 0);
